import { mergeJSON } from '../utils/zcutils';
import { getMarkerConfig } from './markerOptions';
import { getAnimationConf } from '../utils/animationutils';

export function setBoxplotBuilderConfig() {
    let seriesOptions = this.config.series,
        commonOptions = this.config.common,
        animationOptions = this.builderC.animationOptions;

    this.builderC.median =
        seriesOptions && seriesOptions.median ? mergeJSON(commonOptions.median, seriesOptions.median, true) : commonOptions.median;
    this.builderC.medianOptionsMerged = getMarkerConfig(this.builderC.median, animationOptions);
}
